```class Solution {
public:
    int getMaxRepetitions(string s1, int n1, string s2, int n2) {
        int len1 = s1.length(), len2 = s2.length();
        int count1 = 0, count2 = 0, match = 0;
        for (int i = 0; i < n1 * len1; i++) {
            for (int j = 0; j < len2 && i < n1 * len1; j++) {
                if (s1[i % len1] == s2[j]) {
                    i++;
                    match++;
                    if (match == len2) {
                        count2++;
                        match = 0;
                    }
                }
            }
        }
        return count2 / n2;
    }
};```
